// ---------------------------------------------------------------------------
// LtrStatsPath (ltr.stats)
// ---------------------------------------------------------------------------

// LtrStatsPath builds URL paths for the ltr.stats operation.
//
// Provides information about the current status of the LTR plugin.
//
// Available: >= 2.19.0
type LtrStatsPath struct {
	NodeID []string
	Stat   []string
}

func (p LtrStatsPath) Build() (string, error) {
	pb := acquire()
	pb.writeLit("_plugins")
	pb.writeLit("_ltr")
	switch {
	case hasNonEmpty(p.NodeID) && hasNonEmpty(p.Stat):
		writeSegments(pb, p.NodeID)
		pb.writeLit("stats")
		writeSegments(pb, p.Stat)
	case hasNonEmpty(p.NodeID):
		writeSegments(pb, p.NodeID)
		pb.writeLit("stats")
	case hasNonEmpty(p.Stat):
		pb.writeLit("stats")
		writeSegments(pb, p.Stat)
	default:
		pb.writeLit("stats")
	}
	return pb.release(), nil
}

