// ---------------------------------------------------------------------------
// MlGetStatsPath (ml.get_stats)
// ---------------------------------------------------------------------------

// MlGetStatsPath builds URL paths for the ml.get_stats operation.
//
// Get stats.
//
// Available: >= 1.3.0
type MlGetStatsPath struct {
	NodeID string
	Stat   []string
}

func (p MlGetStatsPath) Build() (string, error) {
	pb := acquire()
	pb.writeLit("_plugins")
	pb.writeLit("_ml")
	switch {
	case p.NodeID != "" && hasNonEmpty(p.Stat):
		pb.writeReq(p.NodeID)
		pb.writeLit("stats")
		writeSegments(pb, p.Stat)
	case p.NodeID != "":
		pb.writeReq(p.NodeID)
		pb.writeLit("stats")
	case hasNonEmpty(p.Stat):
		pb.writeLit("stats")
		writeSegments(pb, p.Stat)
	default:
		pb.writeLit("stats")
	}
	return pb.release(), nil
}

