// ---------------------------------------------------------------------------
// NodesStatsPath (nodes.stats)
// ---------------------------------------------------------------------------

// NodesStatsPath builds URL paths for the nodes.stats operation.
//
// Returns statistical information about nodes in the cluster.
//
// Available: >= 1.0.0
//
// See: https://opensearch.org/docs/latest/api-reference/nodes-apis/nodes-usage/
type NodesStatsPath struct {
	NodeID      []string
	Metric      []string
	IndexMetric []string
}

func (p NodesStatsPath) Build() (string, error) {
	pb := acquire()
	pb.writeLit("_nodes")
	switch {
	case hasNonEmpty(p.NodeID) && hasNonEmpty(p.Metric) && hasNonEmpty(p.IndexMetric):
		writeSegments(pb, p.NodeID)
		pb.writeLit("stats")
		writeSegments(pb, p.Metric)
		writeSegments(pb, p.IndexMetric)
	case hasNonEmpty(p.Metric) && hasNonEmpty(p.IndexMetric):
		pb.writeLit("stats")
		writeSegments(pb, p.Metric)
		writeSegments(pb, p.IndexMetric)
	case hasNonEmpty(p.NodeID) && hasNonEmpty(p.Metric):
		writeSegments(pb, p.NodeID)
		pb.writeLit("stats")
		writeSegments(pb, p.Metric)
	case hasNonEmpty(p.Metric):
		pb.writeLit("stats")
		writeSegments(pb, p.Metric)
	case hasNonEmpty(p.NodeID):
		writeSegments(pb, p.NodeID)
		pb.writeLit("stats")
	default:
		if hasNonEmpty(p.NodeID) || hasNonEmpty(p.Metric) || hasNonEmpty(p.IndexMetric) {
			return "", explainNodesStatsPath(p)
		}
		pb.writeLit("stats")
	}
	return pb.release(), nil
}

// explainNodesStatsPath returns a specific error describing why the
// caller's field combination does not match any spec path variant. The
// switch in NodesStatsPath.Build dispatches here from its
// default: case after confirming at least one optional field is set.
func explainNodesStatsPath(p NodesStatsPath) error {
	if hasNonEmpty(p.IndexMetric) && !hasNonEmpty(p.Metric) {
		return fmt.Errorf("NodesStatsPath.IndexMetric requires NodesStatsPath.Metric: %w", errRequired)
	}
	return fmt.Errorf("NodesStatsPath: invalid combination of fields: %w", errRequired)
}

