// ---------------------------------------------------------------------------
// SnapshotStatusPath (snapshot.status)
// ---------------------------------------------------------------------------

// SnapshotStatusPath builds URL paths for the snapshot.status operation.
//
// Returns information about the status of a snapshot.
//
// Available: >= 1.0.0
//
// See: https://opensearch.org/docs/latest/api-reference/snapshots/get-snapshot-status/
type SnapshotStatusPath struct {
	Repository string
	Snapshot   []string
}

func (p SnapshotStatusPath) Build() (string, error) {
	pb := acquire()
	pb.writeLit("_snapshot")
	switch {
	case p.Repository != "" && hasNonEmpty(p.Snapshot):
		pb.writeReq(p.Repository)
		writeSegments(pb, p.Snapshot)
	case p.Repository != "":
		pb.writeReq(p.Repository)
	default:
		if p.Repository != "" || hasNonEmpty(p.Snapshot) {
			return "", explainSnapshotStatusPath(p)
		}
	}
	pb.writeLit("_status")
	return pb.release(), nil
}

// explainSnapshotStatusPath returns a specific error describing why the
// caller's field combination does not match any spec path variant. The
// switch in SnapshotStatusPath.Build dispatches here from its
// default: case after confirming at least one optional field is set.
func explainSnapshotStatusPath(p SnapshotStatusPath) error {
	if hasNonEmpty(p.Snapshot) && p.Repository == "" {
		return fmt.Errorf("SnapshotStatusPath.Snapshot requires SnapshotStatusPath.Repository: %w", errRequired)
	}
	return fmt.Errorf("SnapshotStatusPath: invalid combination of fields: %w", errRequired)
}

